9	class FetchEvent {
10	  // TODO(after): get rid of the 'internal' variant and always use an external waitUntil
11	  // (this means removing `FetchEventResult.waitUntil` which also requires a builder change)
12	  readonly [waitUntilSymbol]:
13	    | { kind: 'internal'; promises: Promise<any>[] }
14	    | { kind: 'external'; function: WaitUntil };
15	
16	  [responseSymbol]?: Promise<Response>;
17	  [passThroughSymbol] = false
18	
19	  constructor(_request: Request, waitUntil?: WaitUntil) {
20	    this[waitUntilSymbol] = waitUntil
21	      ? { kind: 'external', function: waitUntil }
22	      : { kind: 'internal', promises: [] }
23	  }
24	
25	  // TODO: is this dead code? NextFetchEvent never lets this get called
26	  respondWith(response: Response | Promise<Response>): void {
27	    if (!this[responseSymbol]) {
28	      this[responseSymbol] = Promise.resolve(response)
29	    }
30	  }
31	
32	  // TODO: is this dead code? passThroughSymbol is unused
33	  passThroughOnException(): void {
34	    this[passThroughSymbol] = true
35	  }
36	
37	  waitUntil(promise: Promise<any>): void {
38	    if (this[waitUntilSymbol].kind === 'external') {
39	      // if we received an external waitUntil, we delegate to it
40	      // TODO(after): this will make us not go through `getServerError(error, 'edge-server')` in `sandbox`
41	      const waitUntil = this[waitUntilSymbol].function
42	      return waitUntil(promise)
43	    } else {
44	      // if we didn't receive an external waitUntil, we make it work on our own
45	      // (and expect the caller to do something with the promises)
46	      this[waitUntilSymbol].promises.push(promise)
47	    }
48	  }
49	}
50	
51	export function getWaitUntilPromiseFromEvent(
52	  event: FetchEvent
53	): Promise<void> | undefined {
54	  return event[waitUntilSymbol].kind === 'internal'
55	    ? Promise.all(event[waitUntilSymbol].promises).then(() => {})
56	    : undefined
57	}
