66	  }) {
67	    super(params.request, params.context?.waitUntil)
68	    this.sourcePage = params.page
69	  }
70	
71	  /**
72	   * @deprecated The `request` is now the first parameter and the API is now async.
73	   *
74	   * Read more: https://nextjs.org/docs/messages/middleware-new-signature
75	   */
