9	/**
10	 * @internal
11	 */
12	export class ReadonlyRequestCookiesError extends Error {
13	  constructor() {
14	    super(
15	      'Cookies can only be modified in a Server Action or Route Handler. Read more: https://nextjs.org/docs/app/api-reference/functions/cookies#options'
16	    )
17	  }
18	
19	  public static callable() {
20	    throw new ReadonlyRequestCookiesError()
21	  }
22	}
23	
24	// We use this to type some APIs but we don't construct instances directly
25	export type { ResponseCookies }
26	
27	// The `cookies()` API is a mix of request and response cookies. For `.get()` methods,
28	// we want to return the request cookie if it exists. For mutative methods like `.set()`,
29	// we want to return the response cookie.
30	export type ReadonlyRequestCookies = Omit<
31	  RequestCookies,
32	  'set' | 'clear' | 'delete'
33	> &
34	  Pick<ResponseCookies, 'set' | 'delete'>
35	
36	export class RequestCookiesAdapter {
37	  public static seal(cookies: RequestCookies): ReadonlyRequestCookies {
38	    return new Proxy(cookies as any, {
39	      get(target, prop, receiver) {
40	        switch (prop) {
41	          case 'clear':
42	          case 'delete':
43	          case 'set':
44	            return ReadonlyRequestCookiesError.callable
45	          default:
46	            return ReflectAdapter.get(target, prop, receiver)
47	        }
48	      },
49	    })
50	  }
51	}
52	
53	const SYMBOL_MODIFY_COOKIE_VALUES = Symbol.for('next.mutated.cookies')
54	
55	export function getModifiedCookieValues(
56	  cookies: ResponseCookies
57	): ResponseCookie[] {
58	  const modified: ResponseCookie[] | undefined = (cookies as unknown as any)[
59	    SYMBOL_MODIFY_COOKIE_VALUES
60	  ]
61	  if (!modified || !Array.isArray(modified) || modified.length === 0) {
62	    return []
63	  }
64	
65	  return modified
66	}
67	
68	type SetCookieArgs =
69	  | [key: string, value: string, cookie?: Partial<ResponseCookie>]
70	  | [options: ResponseCookie]
71	
72	export function appendMutableCookies(
73	  headers: Headers,
74	  mutableCookies: ResponseCookies
75	): boolean {
76	  const modifiedCookieValues = getModifiedCookieValues(mutableCookies)
77	  if (modifiedCookieValues.length === 0) {
78	    return false
79	  }
80	
81	  // Return a new response that extends the response with
82	  // the modified cookies as fallbacks. `res` cookies
83	  // will still take precedence.
84	  const resCookies = new ResponseCookies(headers)
85	  const returnedCookies = resCookies.getAll()
86	
87	  // Set the modified cookies as fallbacks.
88	  for (const cookie of modifiedCookieValues) {
89	    resCookies.set(cookie)
90	  }
91	
92	  // Set the original cookies as the final values.
93	  for (const cookie of returnedCookies) {
94	    resCookies.set(cookie)
95	  }
96	
97	  return true
98	}
99	
100	type ResponseCookie = NonNullable<
101	  ReturnType<InstanceType<typeof ResponseCookies>['get']>
102	>
103	
104	export class MutableRequestCookiesAdapter {
105	  public static wrap(
106	    cookies: RequestCookies,
107	    onUpdateCookies?: (cookies: string[]) => void
108	  ): ResponseCookies {
109	    const responseCookies = new ResponseCookies(new Headers())
110	    for (const cookie of cookies.getAll()) {
111	      responseCookies.set(cookie)
112	    }
113	
114	    let modifiedValues: ResponseCookie[] = []
115	    const modifiedCookies = new Set<string>()
116	    const updateResponseCookies = () => {
117	      // TODO-APP: change method of getting workStore
118	      const workStore = workAsyncStorage.getStore()
119	      if (workStore) {
120	        workStore.pathWasRevalidated = ActionDidRevalidateStaticAndDynamic
121	      }
122	
123	      const allCookies = responseCookies.getAll()
124	      modifiedValues = allCookies.filter((c) => modifiedCookies.has(c.name))
125	      if (onUpdateCookies) {
126	        const serializedCookies: string[] = []
127	        for (const cookie of modifiedValues) {
128	          const tempCookies = new ResponseCookies(new Headers())
129	          tempCookies.set(cookie)
130	          serializedCookies.push(tempCookies.toString())
131	        }
132	
133	        onUpdateCookies(serializedCookies)
134	      }
135	    }
136	
137	    const wrappedCookies = new Proxy(responseCookies, {
138	      get(target, prop, receiver) {
139	        switch (prop) {
140	          // A special symbol to get the modified cookie values
141	          case SYMBOL_MODIFY_COOKIE_VALUES:
142	            return modifiedValues
143	
144	          // TODO: Throw error if trying to set a cookie after the response
145	          // headers have been set.
146	          case 'delete':
147	            return function (...args: [string] | [ResponseCookie]) {
148	              modifiedCookies.add(
149	                typeof args[0] === 'string' ? args[0] : args[0].name
150	              )
151	              try {
152	                target.delete(...args)
153	                return wrappedCookies
154	              } finally {
155	                updateResponseCookies()
156	              }
157	            }
158	          case 'set':
159	            return function (...args: SetCookieArgs) {
160	              modifiedCookies.add(
161	                typeof args[0] === 'string' ? args[0] : args[0].name
162	              )
163	              try {
164	                target.set(...args)
165	                return wrappedCookies
166	              } finally {
167	                updateResponseCookies()
168	              }
169	            }
170	
171	          default:
172	            return ReflectAdapter.get(target, prop, receiver)
173	        }
174	      },
175	    })
176	
177	    return wrappedCookies
178	  }
179	}
180	
181	export function createCookiesWithMutableAccessCheck(
182	  requestStore: RequestStore
183	): ResponseCookies {
184	  const wrappedCookies = new Proxy(requestStore.mutableCookies, {
185	    get(target, prop, receiver) {
186	      switch (prop) {
187	        case 'delete':
188	          return function (...args: [string] | [ResponseCookie]) {
189	            ensureCookiesAreStillMutable(requestStore, 'cookies().delete')
190	            target.delete(...args)
191	            return wrappedCookies
192	          }
193	        case 'set':
194	          return function (...args: SetCookieArgs) {
195	            ensureCookiesAreStillMutable(requestStore, 'cookies().set')
196	            target.set(...args)
197	            return wrappedCookies
198	          }
199	
200	        default:
201	          return ReflectAdapter.get(target, prop, receiver)
202	      }
203	    },
204	  })
205	  return wrappedCookies
206	}
207	
208	export function areCookiesMutableInCurrentPhase(requestStore: RequestStore) {
209	  return requestStore.phase === 'action'
210	}
211	
212	/** Ensure that cookies() starts throwing on mutation
213	 * if we changed phases and can no longer mutate.
214	 *
215	 * This can happen when going:
216	 *   'render' -> 'after'
217	 *   'action' -> 'render'
218	 * */
219	function ensureCookiesAreStillMutable(
220	  requestStore: RequestStore,
221	  _callingExpression: string
222	) {
223	  if (!areCookiesMutableInCurrentPhase(requestStore)) {
224	    // TODO: maybe we can give a more precise error message based on callingExpression?
225	    throw new ReadonlyRequestCookiesError()
226	  }
227	}
228	
229	export function responseCookiesToRequestCookies(
230	  responseCookies: ResponseCookies
231	): RequestCookies {
232	  const requestCookies = new RequestCookies(new Headers())
233	  for (const cookie of responseCookies.getAll()) {
234	    requestCookies.set(cookie)
235	  }
236	  return requestCookies
237	}
