# Plan: Add `next/geo` Utility Module

## Context

The Next.js framework exposes `next/server` as a public entry point with middleware utilities like `userAgent`. There is no equivalent geolocation utility, leaving users to hand-roll CDN header parsing for every project. This plan adds a `next/geo` module following the same patterns as `next/server` / `userAgent`.

---

## Critical Files

| File | Role |
|---|---|
| `packages/next/server.js` | **Reference** – CJS entry point pattern to replicate |
| `packages/next/server.d.ts` | **Reference** – `.d.ts` entry point pattern to replicate |
| `packages/next/src/server/web/spec-extension/user-agent.ts` | **Reference** – implementation pattern to replicate |
| `packages/next/package.json` | **Edit** – add `geo.js` and `geo.d.ts` to `files` array |
| `packages/next/geo.js` | **Create** – new CJS public entry point |
| `packages/next/geo.d.ts` | **Create** – new TypeScript declarations entry point |
| `packages/next/src/server/web/spec-extension/geo.ts` | **Create** – core implementation |
| `packages/next/src/server/web/spec-extension/geo.test.ts` | **Create** – Jest test suite |

---

## Step-by-Step Implementation

### Step 1 – Core implementation: `packages/next/src/server/web/spec-extension/geo.ts`

Create this file. It contains all logic and exports. Mirrors the structure of `user-agent.ts` but is self-contained (no external deps).

```typescript
const COUNTRY_NAMES: Record<string, string> = {
  AU: 'Australia',
  BR: 'Brazil',
  CA: 'Canada',
  CN: 'China',
  DE: 'Germany',
  FR: 'France',
  GB: 'United Kingdom',
  IN: 'India',
  JP: 'Japan',
  US: 'United States',
}

export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

export function geoFromHeaders(headers: Headers): Geo {
  const city = headers.get('x-vercel-ip-city') ?? undefined
  const countryCode =
    headers.get('x-vercel-ip-country') ??
    headers.get('cf-ipcountry') ??
    undefined
  const region = headers.get('x-vercel-ip-country-region') ?? undefined
  const latitude = headers.get('x-vercel-ip-latitude') ?? undefined
  const longitude = headers.get('x-vercel-ip-longitude') ?? undefined
  const timezone = headers.get('x-vercel-ip-timezone') ?? undefined
  const country = countryCode
    ? COUNTRY_NAMES[countryCode.toUpperCase()]
    : undefined

  return { city, country, countryCode, region, latitude, longitude, timezone }
}

export function geo({ headers }: { headers: Headers }): Geo {
  return geoFromHeaders(headers)
}

export function isInRegion(geo: Geo, regions: string[]): boolean {
  if (!geo.countryCode) return false
  const code = geo.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371
  const toRad = (deg: number) => (deg * Math.PI) / 180
  const dLat = toRad(parseFloat(lat2) - parseFloat(lat1))
  const dLon = toRad(parseFloat(lon2) - parseFloat(lon1))
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(parseFloat(lat1))) *
      Math.cos(toRad(parseFloat(lat2))) *
      Math.sin(dLon / 2) ** 2
